func process(data []Item) string {
    var parts []string
    for _, item := range data {
        if s := processItem(item); s != "" {
            parts = append(parts, s)
        }
    }
    return strings.Join(parts, "")
}

func processItem(item Item) string {
    if !item.Active || item.Type != "A" {
        return ""
    }
    if item.Value > 10 {
        return handle(item)
    }
    return fallback(item)
}
